import { NextRequest, NextResponse } from 'next/server';
import { verifyToken } from '@/lib/auth';
import { importTranslationsFromFiles, exportTranslationsToFiles } from '@/lib/translation-sync';

// POST /api/admin/translations/sync - Sync translations between database and files
export async function POST(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { direction } = await request.json();

    if (direction === 'import') {
      // Import from JSON files to database
      await importTranslationsFromFiles();
      return NextResponse.json({ 
        success: true, 
        message: 'Translations imported from files to database' 
      });
    } else if (direction === 'export') {
      // Export from database to JSON files
      await exportTranslationsToFiles();
      return NextResponse.json({ 
        success: true, 
        message: 'Translations exported from database to files' 
      });
    } else {
      return NextResponse.json({ error: 'Invalid direction. Use "import" or "export"' }, { status: 400 });
    }
  } catch (error) {
    console.error('Translation sync error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}